// Main ChatWindow component
const ChatWindow = ({ messages, onSendMessage, onButtonClick, inputType, currentUser, isProcessing }) => {
  const [input, setInput] = useState('');
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [menuCategories, setMenuCategories] = useState([]);
  const [paymentDetails, setPaymentDetails] = useState({
    cardNumber: "",
    expiryDate: "",
    cvv: "",
    name: ""
  });
  
  // State variables for quantity selection
  const [selectedQuantity, setSelectedQuantity] = useState(1);
  const [showQuantitySelector, setShowQuantitySelector] = useState(false);
  const [selectedDrink, setSelectedDrink] = useState(null);
  const [showOrderConfirmation, setShowOrderConfirmation] = useState(false);
  
  // State for festival guide
  const [showFestivalGuide, setShowFestivalGuide] = useState(false);
  
  // State for featured vendors
  const [showFeaturedVendors, setShowFeaturedVendors] = useState(false);
  
  // State for festival map
  const [showFestivalMap, setShowFestivalMap] = useState(false);
  
  // State for vendor menu
  const [selectedVendor, setSelectedVendor] = useState(null);
  const [showVendorMenu, setShowVendorMenu] = useState(false);
  
  const messagesEndRef = useRef(null);
  // Menu data removed - POS systems handle menus

  // Debug: Log state changes for festival guide
  useEffect(() => {
    console.log("showFestivalGuide changed to:", showFestivalGuide);
  }, [showFestivalGuide]);

  // Menu functionality removed - POS systems handle menus

  // Auto-scroll to bottom when messages change
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Format phone number as the user types
  const formatPhoneNumber = (value) => {
    const phone = value.replace(/\D/g, '');
    if (phone.length < 4) return phone;
    if (phone.length < 7) return `(${phone.slice(0,3)}) ${phone.slice(3)}`;
    return `(${phone.slice(0,3)}) ${phone.slice(3,6)}-${phone.slice(6,10)}`;
  };

  // Handle user input in the chat input field
  const handleInputChange = (e) => {
    let value = e.target.value;
    if (inputType === 'phone') {
      value = formatPhoneNumber(value);
    }
    setInput(value);
  };

  // Handle form submission for the chat input
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    
    // Keep the existing behavior
    onSendMessage(input);
    
    // Add just this SMS functionality for phone input type
    if (inputType === 'phone') {
      // Generate and send verification code
      const code = generateVerificationCode();
      sendVerificationCode(input, code);
      storeVerificationCode(input, code);
    }
    
    setInput('');
  };

  // Handle category selection
  const handleCategorySelect = (categoryId) => {
    setSelectedCategory(categoryId === selectedCategory ? null : categoryId);
  };

  // Format card number with spaces as the user types
  const formatCardNumber = (value) => {
    const v = value.replace(/\s+/g, "").replace(/[^0-9]/gi, "");
    const matches = v.match(/\d{4,16}/g);
    const match = (matches && matches[0]) || "";
    const parts = [];

    for (let i = 0, len = match.length; i < len; i += 4) {
      parts.push(match.substring(i, i + 4));
    }

    if (parts.length) {
      return parts.join(" ");
    } else {
      return value;
    }
  };

  // Format expiry date as the user types
  const formatExpiryDate = (value) => {
    const v = value.replace(/\s+/g, "").replace(/[^0-9]/gi, "");
    if (v.length >= 2) {
      return v.slice(0, 2) + "/" + v.slice(2, 4);
    }
    return v;
  };

  // Handle input changes in the payment form
  const handlePaymentInputChange = (field, value) => {
    let formattedValue = value;
    
    if (field === 'cardNumber') {
      formattedValue = formatCardNumber(value);
    } else if (field === 'expiryDate') {
      formattedValue = formatExpiryDate(value);
    }
    
    setPaymentDetails(prev => ({
      ...prev,
      [field]: formattedValue
    }));
  };

  // Handle drink selection
  const handleDrinkSelection = (drinkJson, type = 'selection') => {
    const drink = JSON.parse(drinkJson);
    setSelectedDrink(drink);
    setSelectedQuantity(1);
    setShowQuantitySelector(true);
    setShowOrderConfirmation(false);
  };

  // Handle selecting an item from the festival guide
  const handleItemFromGuide = (item) => {
    console.log("Selected item from guide:", item);
    
    // Hide the festival guide
    setShowFestivalGuide(false);
    
    // Handle different types of selections
    if (item.action === 'show_menu') {
      // Show the menu for the selected category
      onButtonClick('show_menu');
    } else if (item.type) {
      // Handle category-specific actions
      onButtonClick(`show_${item.type}`);
    }
  };

  // Handle selecting a vendor from featured vendors
  const handleVendorFromFeatured = (vendor) => {
    console.log("Selected vendor from featured:", vendor);
    
    // Hide the featured vendors
    setShowFeaturedVendors(false);
    
    // Handle different vendor actions
    if (vendor.action === 'show_vendor_menu') {
      // Show the specific vendor's menu
      onButtonClick('show_menu', { vendor: vendor.id });
    } else if (vendor.action === 'show_full_menu') {
      // Show the full festival menu
      onButtonClick('show_menu');
    }
  };

  // Handle selecting a vendor from festival map
  const handleVendorFromMap = (vendor) => {
    console.log("Selected vendor from map:", vendor);
    
    // Hide the festival map
    setShowFestivalMap(false);
    
    // Check if this vendor has Square integration
    const squareVendors = ['bbq-smokehouse', 'craft-cocktails', 'taco-fiesta'];
    
    if (squareVendors.includes(vendor.id)) {
      // Show Square menu for this vendor
      setSelectedVendor(vendor);
      setShowVendorMenu(true);
    } else {
      // Handle vendor selection with original behavior
      if (vendor.action === 'show_vendor_menu') {
        // Show the specific vendor's menu
        onButtonClick('show_menu', { vendor: vendor.id });
      }
    }
  };

  // Handle quantity selection
  const handleQuantitySelect = (quantity) => {
    setSelectedQuantity(quantity);
  };

  // Handle confirming quantity
  const handleConfirmQuantity = () => {
    handleProceedToPayment();
  };

  // Handle proceeding to payment
  const handleProceedToPayment = () => {
    // Create enhanced drink object with quantity information
    const enhancedDrink = {
      ...selectedDrink,
      quantity: selectedQuantity,
      totalPrice: (parseFloat(selectedDrink.price) * selectedQuantity).toFixed(2)
    };
    
    // Reset states
    setShowOrderConfirmation(false);
    setShowQuantitySelector(false);
    
    // Send the enhanced drink data for payment processing
    onSendMessage(JSON.stringify(enhancedDrink), 'enhanced-selection');
  };

  // Handle payment form submission
  const handlePaymentSubmit = (e, paymentData) => {
    e.preventDefault();
    
    // Validate form fields
    if (!paymentDetails.cardNumber || !paymentDetails.expiryDate || !paymentDetails.cvv || !paymentDetails.name) {
      alert("Please fill in all payment fields.");
      return;
    }
    
    // Send payment details to parent component
    onSendMessage(JSON.stringify(paymentDetails), 'payment-submit');
    
    // Reset form
    setPaymentDetails({
      cardNumber: "",
      expiryDate: "",
      cvv: "",
      name: ""
    });
  };

  // Handle vendor menu close
  const handleVendorMenuClose = () => {
    setShowVendorMenu(false);
    setSelectedVendor(null);
  };

  // Handle vendor order completion
  const handleVendorOrderComplete = (orderResult) => {
    console.log('Vendor order completed:', orderResult);
    setShowVendorMenu(false);
    setSelectedVendor(null);
    
    // Send success message to chat
    onSendMessage(`Great! Your order from ${selectedVendor?.name} has been placed successfully. Order ID: ${orderResult.orderId}`);
  };

  // Handle payment cancellation
  const handlePaymentCancel = (e) => {
    e.preventDefault();
    onSendMessage('cancelled', 'payment-cancel');
    
    // Reset form
    setPaymentDetails({
      cardNumber: "",
      expiryDate: "",
      cvv: "",
      name: ""
    });
  };

  // Render quantity selector
  const renderQuantitySelector = () => {
    if (!showQuantitySelector || !selectedDrink || showFestivalGuide || showFeaturedVendors || showFestivalMap) return null;
    
    return (
      <QuantitySelector>
        <QuantityTitle>How many would you like to order?</QuantityTitle>
        <QuantityButtons>
          {[1, 2, 3, 4].map(qty => (
            <QuantityButton 
              key={qty} 
              selected={selectedQuantity === qty}
              onClick={() => handleQuantitySelect(qty)}
            >
              {qty}
            </QuantityButton>
          ))}
        </QuantityButtons>
        <ButtonGroup>
          <ActionButton onClick={() => setShowQuantitySelector(false)}>
            Cancel
          </ActionButton>
          <ActionButton onClick={handleConfirmQuantity}>
            Confirm
          </ActionButton>
        </ButtonGroup>
      </QuantitySelector>
    );
  };

  // Render order confirmation with upsell
  const renderOrderConfirmation = () => {
    if (!showOrderConfirmation || !selectedDrink || showFestivalGuide || showFeaturedVendors || showFestivalMap) return null;
    
    const totalPrice = (parseFloat(selectedDrink.price) * selectedQuantity).toFixed(2);
    
    return (
      <OrderSummary>
        <QuantityTitle>Confirm Your Order</QuantityTitle>
        <OrderSummaryItem>
          <span>{selectedDrink.name}</span>
          <span>${selectedDrink.price}</span>
        </OrderSummaryItem>
        <OrderSummaryItem>
          <span>Quantity</span>
          <span>{selectedQuantity}</span>
        </OrderSummaryItem>
        <OrderTotal>
          <span>Total</span>
          <span>${totalPrice}</span>
        </OrderTotal>
        
        {/* Upsell section */}
        <UpsellContainer>
          <UpsellTitle>Would you like to add anything else?</UpsellTitle>
          <UpsellButtons>
            <ActionButton onClick={() => onButtonClick('show_food_menu')}>
              Add Food
            </ActionButton>
            <ActionButton onClick={() => onButtonClick('show_drinks')}>
              Add More Drinks
            </ActionButton>
            <ActionButton onClick={() => onButtonClick('show_desserts')}>
              Add Dessert
            </ActionButton>
          </UpsellButtons>
        </UpsellContainer>
        
        <ButtonGroup>
          <ActionButton onClick={() => {
            setShowOrderConfirmation(false);
            setShowQuantitySelector(true);
          }}>
            Edit
          </ActionButton>
          <GoldButton onClick={handleProceedToPayment}>
            Proceed to Payment
          </GoldButton>
        </ButtonGroup>
      </OrderSummary>
    );
  };

  // Render menu categories
  const renderDynamicMenuCategories = () => {
    if (menuCategories.length === 0) {
      return <p style={{ color: '#AAA', fontStyle: 'italic' }}>Loading menu categories...</p>;
    }

    return (
      <CategorySelector>
        {menuCategories.map(category => (
          <CategoryButton 
            key={category.id}
            className={selectedCategory === category.id ? 'active' : ''}
            onClick={() => handleCategorySelect(category.id)}
          >
            {category.name}
          </CategoryButton>
        ))}
      </CategorySelector>
    );
  };

  // Menu functionality removed - POS systems handle menus
  const renderMenuItems = () => {
    return <p style={{ color: '#AAA', fontStyle: 'italic' }}>Menu available through POS systems</p>;
  };

  // Render the payment form
  const renderPaymentForm = (message) => {
    const { paymentData } = message;
    
    // Support for quantity-based pricing
    const totalAmount = paymentData.totalPrice || paymentData.amount;
    const itemName = paymentData.quantity 
      ? `${paymentData.drinkName || paymentData.name} (x${paymentData.quantity})`
      : (paymentData.drinkName || paymentData.name);
    
    return (
      <PaymentFormContainer>
        <PaymentFormTitle>Payment Details</PaymentFormTitle>
        
        <OrderSummary>
          <p style={{ marginBottom: '8px', fontWeight: '500' }}>Order Summary</p>
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span>{itemName}</span>
            <span style={{ fontWeight: 'bold', color: '#D4AF37' }}>${totalAmount}</span>
          </div>
        </OrderSummary>
        
        <form onSubmit={(e) => handlePaymentSubmit(e, paymentData)}>
          <FormGroup>
            <FormLabel>Cardholder Name</FormLabel>
            <FormInput 
              type="text"
              placeholder="John Doe"
              value={paymentDetails.name}
              onChange={(e) => handlePaymentInputChange('name', e.target.value)}
              disabled={isProcessing}
            />
          </FormGroup>
          
          <FormGroup>
            <FormLabel>Card Number</FormLabel>
            <FormInput 
              type="text"
              placeholder="1234 5678 9012 3456"
              value={paymentDetails.cardNumber}
              onChange={(e) => handlePaymentInputChange('cardNumber', e.target.value)}
              maxLength="19"
              disabled={isProcessing}
            />
          </FormGroup>
          
          <FormRow>
            <FormColumn>
              <FormLabel>Expiry Date</FormLabel>
              <FormInput 
                type="text"
                placeholder="MM/YY"
                value={paymentDetails.expiryDate}
                onChange={(e) => handlePaymentInputChange('expiryDate', e.target.value)}
                maxLength="5"
                disabled={isProcessing}
              />
            </FormColumn>
            
            <FormColumn>
              <FormLabel>CVV</FormLabel>
              <FormInput 
                type="password"
                placeholder="123"
                value={paymentDetails.cvv}
                onChange={(e) => handlePaymentInputChange('cvv', e.target.value)}
                maxLength="4"
                disabled={isProcessing}
              />
            </FormColumn>
          </FormRow>
          
          <PaymentFormButtons>
            <CancelButton 
              type="button" 
              onClick={handlePaymentCancel}
              disabled={isProcessing}
            >
              Cancel
            </CancelButton>
            <PayButton 
              type="submit"
              disabled={isProcessing}
            >
              {isProcessing ? 'Processing...' : `Pay ${totalAmount}`}
            </PayButton>
          </PaymentFormButtons>
        </form>
      </PaymentFormContainer>
    );
  };

  // Render message content based on message type
  const renderMessageContent = (message) => {
    // Handle payment form
    if (message.showPaymentForm && message.paymentData) {
      return (
        <>
          <p>{message.text}</p>
          {renderPaymentForm(message)}
        </>
      );
    }

    if (message.preferenceQuestion) {
      return (
        <>
          <p>{message.text}</p>
          <PreferenceQuestion 
            question={message.text}
            options={message.options}
            onSelect={(optionId) => {
              const actionType = `preference_${message.questionId}_${optionId}`;
              onButtonClick(actionType);
            }}
          />
        </>
      );
    }
    
    // Menu display removed - POS systems handle menus
    if (false) {
      return (
        <DrinkMenu>
          <p style={{ marginBottom: '8px', fontWeight: '500', color: 'white' }}>What would you like to order?</p>
          {renderDynamicMenuCategories()}
          {renderMenuItems()}
        </DrinkMenu>
      );
    }
    
    // Handle drink search
    if (message.showDrinkMenu) {
      return (
        <DrinkMenu>
          <DrinkSearchAutocomplete onSelect={(drink) => handleDrinkSelection(JSON.stringify(drink))} />
        </DrinkMenu>
      );
    }
    
    // Handle vendor marketplace
    if (message.showVendorMarketplace) {
      return (
        <>
          <p>{message.text}</p>
          <ButtonGroup>
            <ActionButton onClick={() => onButtonClick('show_vendor_marketplace')}>
              🎪 Open Live Vendor Marketplace
            </ActionButton>
          </ButtonGroup>
        </>
      );
    }
    
    // Handle history items
    if (message.historyItems && message.historyItems.length > 0) {
      return (
        <>
          <p>{message.text}</p>
          <HistoryTitle>Your Previous Order:</HistoryTitle>
          <HistoryItemsContainer>
            {message.historyItems.map((item, idx) => (
              <HistoryItem key={idx}>
                <HistoryItemDetails>
                  <HistoryItemName>
                    {item.quantity > 1 ? `${item.quantity}x ` : ''}
                    {item.name}
                  </HistoryItemName>
                  {item.type && <HistoryItemType>{item.type}</HistoryItemType>}
                </HistoryItemDetails>
                <HistoryItemPrice>${parseFloat(item.price).toFixed(2)}</HistoryItemPrice>
                <ReorderButton onClick={() => onButtonClick('reorder_item', item)}>
                  Reorder
                </ReorderButton>
              </HistoryItem>
            ))}
          </HistoryItemsContainer>
          {message.buttons && (
            <ButtonGroup>
              {message.buttons.map((button, btnIndex) => (
                <ActionButton
                  key={btnIndex}
                  onClick={() => onButtonClick(button.action, button.data)}
                >
                  {button.text}
                </ActionButton>
              ))}
            </ButtonGroup>
          )}
        </>
      );
    }
    
    // Default message content
    return (
      <>
        <p>{message.text}</p>
        {message.buttons && (
          <ButtonGroup>
            {message.buttons.map((button, btnIndex) => (
              <ActionButton
                key={btnIndex}
                onClick={() => {
                  console.log("Button clicked:", button.action, button.text);
                  
                  // Check for button actions
                  if (button.action === "help me decide" || 
                      button.text === "Help Me Decide") {
                    console.log("Setting showFestivalGuide to true");
                    setShowFestivalGuide(true);
                  } else if (button.action === "featured_vendors" || 
                             button.text === "Featured Food Trucks & Vendors") {
                    console.log("Setting showFeaturedVendors to true");
                    setShowFeaturedVendors(true);
                  } else if (button.action === "festival_map" || 
                             button.text === "Festival Map") {
                    console.log("Setting showFestivalMap to true");
                    setShowFestivalMap(true);
                  } else if (message.requiresPayment) {
                    if (button.action === "show_menu") {
                      onButtonClick(button.action);
                    } else {
                      onSendMessage(button.action);
                    }
                  } else {
                    onButtonClick(button.action);
                  }
                }}
              >
                {button.text}
              </ActionButton>
            ))}
          </ButtonGroup>
        )}
        {message.drinks && (
          <DrinkMenu>
            {message.drinks.map((drink, index) => (
              <DrinkItem key={index} onClick={() => handleDrinkSelection(JSON.stringify(drink))}>
                <DrinkDetails>
                  <h4>{drink.name}</h4>
                  <p>{drink.description}</p>
                </DrinkDetails>
                <DrinkPrice>${drink.price}</DrinkPrice>
              </DrinkItem>
            ))}
          </DrinkMenu>
        )}
        {message.categoryItems && (
          <DrinkMenu>
            <p style={{ marginBottom: '8px', fontWeight: '500', color: 'white' }}>
              {message.categoryName.charAt(0).toUpperCase() + 
               message.categoryName.slice(1).replace(/_/g, ' ').replace(/([A-Z])/g, ' $1').trim()}
            </p>
            {message.categoryItems.map((item, index) => (
              <DrinkItem key={index} onClick={() => handleDrinkSelection(JSON.stringify(item))}>
                <DrinkDetails>
                  <h4>{item.name}</h4>
                  {item.description && <p>{item.description}</p>}
                </DrinkDetails>
                <DrinkPrice>${parseFloat(item.price).toFixed(2)}</DrinkPrice>
              </DrinkItem>
            ))}
          </DrinkMenu>
        )}
      </>
    );
  };
  
  // Check if any message contains an active payment form
  const hasActivePaymentForm = messages.some(message => 
    message.showPaymentForm && message.paymentData && isProcessing
  );

  // Check if any overlay is active
  const hasActiveOverlay = showFestivalGuide || showFeaturedVendors || showFestivalMap;

  /* 
  ================================
  HIDDEN CONVERSATIONAL CHAT FLOW
  ================================
  This section contains the conversational chat interface logic
  that was previously used. It's commented out for future use
  but can be re-enabled by uncommenting this block.
  
  Features included:
  - Natural language conversation flow
  - Message bubbles with avatars
  - Real-time typing indicators
  - Contextual responses
  - Multi-turn dialogue handling
  
  To re-enable: uncomment the entire block below
  
  const [showConversationalMode, setShowConversationalMode] = useState(false);
  const [conversationHistory, setConversationHistory] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  
  const handleConversationalInput = (userInput) => {
    // Add user message to history
    setConversationHistory(prev => [...prev, {
      sender: 'user',
      message: userInput,
      timestamp: new Date()
    }]);
    
    // Simulate bot typing
    setIsTyping(true);
    
    // Process natural language input
    setTimeout(() => {
      const botResponse = processBotResponse(userInput);
      setConversationHistory(prev => [...prev, {
        sender: 'bot',
        message: botResponse,
        timestamp: new Date()
      }]);
      setIsTyping(false);
    }, 1500);
  };
  
  const processBotResponse = (input) => {
    // Natural language processing logic here
    // This would handle contextual responses, recommendations, etc.
    return "I understand you're looking for something special. Let me help you find the perfect option.";
  };
  
  const renderConversationalInterface = () => {
    if (!showConversationalMode) return null;
    
    return (
      <ConversationalContainer>
        <ConversationHeader>
          <h3>Chat with our Festival Guide</h3>
          <CloseButton onClick={() => setShowConversationalMode(false)}>×</CloseButton>
        </ConversationHeader>
        
        <ConversationMessages>
          {conversationHistory.map((msg, index) => (
            <ConversationBubble key={index} sender={msg.sender}>
              <Avatar src={msg.sender === 'bot' ? womanProfileIcon : null} />
              <MessageText>{msg.message}</MessageText>
            </ConversationBubble>
          ))}
          {isTyping && (
            <TypingIndicator>
              <Avatar src={womanProfileIcon} />
              <TypingDots>...</TypingDots>
            </TypingIndicator>
          )}
        </ConversationMessages>
        
        <ConversationInput>
          <InputField 
            placeholder="Ask me anything about the festival..."
            onKeyPress={(e) => {
              if (e.key === 'Enter') {
                handleConversationalInput(e.target.value);
                e.target.value = '';
              }
            }}
          />
        </ConversationInput>
      </ConversationalContainer>
    );
  };
  
  END OF HIDDEN CONVERSATIONAL CHAT FLOW
  ======================================
  */
  
  return (
    <ChatContainer>
      <Logo src={ezdrinkLogo} alt="PourPal Logo" />
      
      <MessagesContainer>
        {messages.map((message, index) => (
          <MessageBubble key={index} sender={message.sender}>
            {message.sender === 'bot' && (
              <Avatar src={womanProfileIcon} alt="Bot Avatar" />
            )}
            <MessageContent>
              {renderMessageContent(message)}
            </MessageContent>
          </MessageBubble>
        ))}
        <div ref={messagesEndRef} />
      </MessagesContainer>
      
      {/* Show festival guide outside the message bubbles if enabled */}
      {showFestivalGuide && (
        <FestivalGuideOverlay>
          <FestivalGuideConversation 
            onSelectItem={handleItemFromGuide}
            onCancel={() => {
              console.log("Canceling festival guide");
              setShowFestivalGuide(false);
              onButtonClick('show_menu');
            }}
          />
        </FestivalGuideOverlay>
      )}
      
      {/* Show featured vendors outside the message bubbles if enabled */}
      {showFeaturedVendors && (
        <FestivalGuideOverlay>
          <FeaturedVendors 
            onSelectVendor={handleVendorFromFeatured}
            onCancel={() => {
              console.log("Canceling featured vendors");
              setShowFeaturedVendors(false);
            }}
          />
        </FestivalGuideOverlay>
      )}

      {/* Show festival map outside the message bubbles if enabled */}
      {showFestivalMap && (
        <FestivalGuideOverlay>
          <FestivalMap 
            onSelectVendor={handleVendorFromMap}
            onClose={() => {
              console.log("Closing festival map");
              setShowFestivalMap(false);
            }}
          />
        </FestivalGuideOverlay>
      )}

      {/* Show vendor menu outside the message bubbles if enabled */}
      {showVendorMenu && selectedVendor && (
        <FestivalGuideOverlay>
          <VendorMenu
            vendor={selectedVendor}
            onClose={handleVendorMenuClose}
            onOrderComplete={handleVendorOrderComplete}
          />
        </FestivalGuideOverlay>
      )}
      
      {/* Show quantity selector and order confirmation outside the message bubbles */}
      {renderQuantitySelector()}
      {renderOrderConfirmation()}
      
      {/* 
      Hidden conversational interface - uncomment to enable
      {renderConversationalInterface()}
      */}
      
      <InputArea>
        <form onSubmit={handleSubmit}>
          <InputRow>
            <InputField
              type={inputType === 'verification' ? 'number' : 'text'}
              value={input}
              onChange={handleInputChange}
              placeholder={
                inputType === 'phone' ? '(555) 555-5555' :
                inputType === 'verification' ? 'Enter verification code' :
                'Type your message...'
              }
              maxLength={inputType === 'phone' ? 14 : undefined}
              disabled={hasActivePaymentForm || showQuantitySelector || showOrderConfirmation || hasActiveOverlay}
            />
            <SendButton 
              type="submit" 
              disabled={hasActivePaymentForm || showQuantitySelector || showOrderConfirmation || hasActiveOverlay}
            >
              Send
            </SendButton>
          </InputRow>
        </form>
      </InputArea>
    </ChatContainer>
  );
};

export default ChatWindow;